function removeEmojis(str) {
  const re = /(?:[\u{1F1E6}-\u{1F1FF}]{2}|[#*0-9]\uFE0F?\u20E3|\p{Extended_Pictographic}(?:\uFE0F|\u200D(?:\p{Extended_Pictographic}|\u2640|\u2642)\uFE0F?)*|\uFE0F|\u200D)/gu;
  return str.replace(re, '');
}


function markdownToBBCode(markdown) {
  return markdown
    // Títulos
    .replace(/^### (.*$)/gim, '[b]$1[/b]')
    .replace(/^## (.*$)/gim, '[b]$1[/b]')
    .replace(/^# (.*$)/gim, '[b]$1[/b]')

    // Negrito
    .replace(/\*\*(.*?)\*\*/g, '[b]$1[/b]')

    // Itálico (opcional, se quiser suportar *texto*)
    .replace(/\*(.*?)\*/g, '[i]$1[/i]')

    // Quebras de linha duplas viram parágrafo
    .replace(/\n{2,}/g, '\n\n')
}

return {
  lead: {
    id: $('Busca dados do Lead').first().json.id,
    analysisBbCodeEncoded: JSON.stringify(markdownToBBCode($input.first().json.output.analysis)),
    analysisWithoutEmojiEncoded: JSON.stringify(removeEmojis($input.first().json.output.analysis)),
