const inputData = $input.all()[0].json;
const workflow = $('BLUEPRINT ENGINE').item.json.workflow;
let currentStageId = $('BLUEPRINT ENGINE').item.json.currentStageId;
let vars = $('BLUEPRINT ENGINE').item.json.vars;
let stageConfig = $('BLUEPRINT ENGINE').item.json.stageConfig;
let outputInstruction = "";

// --- 1. ATUALIZAÇÃO GLOBAL (Check-in) ---
const extractedObj = inputData.output || {};
for (const [key, value] of Object.entries(extractedObj)) {
    if (value !== null && value !== undefined) {
        vars[key] = { value: value, type: 'extracted' };
    }
}

// Helper para verificar se um estágio de Input já está satisfeito
function isInputSatisfied(stage) {
    if (!stage || stage.type !== 'input') return false;
    // Verifica se TODAS as variáveis obrigatórias já existem
    return stage.variables.every(v => vars[v.name] && vars[v.name].value !== null);
}

// --- 2. LOOP DE AVANÇO (Auto-Skip & Look Ahead) ---
let safetyLoop = 0;
let advancing = true;

while (advancing && safetyLoop < 50) {
    stageConfig = workflow[currentStageId];
    if (!stageConfig) break;

    advancing = false; // Assume parada, a menos que prove o contrário

    // --- CASO 1: INPUT (Perguntas) ---
    if (stageConfig.type === 'input') {
        if (isInputSatisfied(stageConfig)) {
            // Já temos a resposta! Pula.
            currentStageId = stageConfig.next_stage;
            advancing = true; 
        } else {
            // Falta resposta. Paramos aqui.
        }
    }

    // --- CASO 2: MENSAGEM (O robô fala) ---
    else if (stageConfig.type === 'message') {
        // [LOOK AHEAD]
        // Verifica se a Próxima Etapa é um Input JÁ RESPONDIDO.
        // Se for, pula a mensagem também.

        const nextStage = workflow[stageConfig.next_stage];

        if (nextStage && nextStage.type === 'input' && isInputSatisfied(nextStage)) {
            currentStageId = nextStage.next_stage;
            advancing = true; // Continua avançando
        } else {
            // Mensagem necessária. Define instrução e para.
            outputInstruction = stageConfig.instruction;
            if (stageConfig.next_stage !== 'STOP') {
                 currentStageId = stageConfig.next_stage;
            }
            advancing = false; 
        }
    }

    // --- CASO 3: ROUTER (Decisão Lógica) ---
    else if (stageConfig.type === 'router') {
        let routeFound = false;
        for (const rule of stageConfig.rules) {
            if (rule.default) {
                currentStageId = rule.default;
                routeFound = true;
                break;
            }
            if (vars[rule.variable] && vars[rule.variable].value === rule.value) {
                currentStageId = rule.next_stage;
                routeFound = true;
                break;
            }
        }
        if (routeFound) advancing = true; 
    }

    safetyLoop++;
}

return {
    newStageId: currentStageId,
    updatedVars: vars,
    finalInstruction: outputInstruction
};

