  WAIT_NAME: { type: "input", variables: [{ name: "name", afterRepliedInstruction: "Diga ao lead que é um prazer conhecê-lo.", description: "Nome do Lead" }], next_stage: "ASK_WANT_DATA_COLLECTION" },
  ASK_WANT_DATA_COLLECTION: { type: "message", instruction: 'Pergunte se aceita participar de uma coleta de dados...', next_stage: "WAIT_WANT_DATA_COLLECTION" }
  // ...rest of your logic exists here when imported
};

const redisData = $("GET Estado Atual1").item.json.propertyName ? JSON.parse($("GET Estado Atual1").item.json.propertyName) : {};
const currentStageId = redisData.stage_id || "START";
const vars = redisData.vars || {};
const stageConfig = workflow[currentStageId] || workflow["START"];

let missingVars = [];
for (const key in workflow) {
  const step = workflow[key];
  if (step.type === "input" && step.variables) {
    step.variables.forEach((v) => {
      if (!vars[v.name] || vars[v.name].value === null) {
        missingVars.push({ name: v.name, description: v.description });
      }
    });
  }
}

return {
  workflow, currentStageId, stageConfig, vars, missingVars,
  userMsg: $("CONCATENA").item.json.user_full_message,
  missingVar: JSON.parse($input.first().json.propertyName || '{}')?.missingVar,
};
